INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (119, 135858, 12, 246, '咖啡厦门网友圣诞联谊活动即将召开！！！', '[HTML]“咖啡圣诞嘉年华会”定于2001年12月22日（星期六）下午14点30分举行，地点：厦门市大同路新路街23-27号（巷口）阳光旗舰PUB（电话：0592-8998496）公共汽车班次（轮渡终点站）：2、3、10、11、25、31等十几路车经过；费用：AA制（预收50元/人）。 本次圣诞聚会安排了丰富的节目：现场抽奖、智力问答、趣味游戏、即兴表演……而且我们的圣诞老人将会给大家分发圣诞小礼物哦！噢……对了，还有一棵美丽的许愿树，让我们共同许下美好的心愿吧！如果朋友们还有什么好的提议请回帖，在此先谢过了！ 现已有以下网友报名参加本次活动：尘末、猫猫龙、SUPPER、小雨、阿海、心瓶、活泼女孩、雅尔、清清小溪、尘儿、水晶米、AA、魔鬼、浪子三少、浅月轻印、妍妍、小灰狼、酌茶听琴、黑夜浪子、白云深、娃娃、静子、风云人物、素芯、扁扁鱼、冥界、山登绝顶、泰山、叶枫、COLA、狂龙、巴乔、小可爱、豆豆、萍萍、梦婕、暮蓝雨、童离、nny、天眼（请要参加的活动的网友继续跟帖，以便于我们活动的安排） “圣诞有什么好活动吗？” “一起来参加‘咖啡厦门网友圣诞联谊’吧！”', '[HTML]“咖啡圣诞嘉年华会”定于2001年12月22日（星期六）下午14点30分举行，地点：厦门市大同路新路街23-27号（巷口）阳光旗舰PUB（电话：0592-8998496）公共汽车班次（轮渡终点站）：2、3、10、11、25、31等十几路车经过；费用：AA制（预收50元/人）。 本次圣诞聚会安排了丰富的节目：现场抽奖、智力问答、趣味游戏、即兴表演……而且我们的圣诞老人将会给大家分发圣诞小礼物哦！噢……对了，还有一棵美丽的许愿树，让我们共同许下美好的心愿吧！如果朋友们还有什么好的提议请回帖，在此先谢过了！ 现已有以下网友报名参加本次活动：尘末、猫猫龙、SUPPER、小雨、阿海、心瓶、活泼女孩、雅尔、清清小溪、尘儿、水晶米、AA、魔鬼、浪子三少、浅月轻印、妍妍、小灰狼、酌茶听琴、黑夜浪子、白云深、娃娃、静子、风云人物、素芯、扁扁鱼、冥界、山登绝顶、泰山、叶枫、COLA、狂龙、巴乔、小可爱、豆豆、萍萍、梦婕、暮蓝雨、童离、nny、天眼（请要参加的活动的网友继续跟帖，以便于我们活动的安排） “圣诞有什么好活动吗？” “一起来参加‘咖啡厦门网友圣诞联谊’吧！”', NULL, '2001-12-05 08:07:00', 8, '20011225190146_bbsid_135858_board_12_6ed06a5c5f.html', '20011225190146');
